                   <img src="https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&q=80&w=100" className="w-full h-full object-cover" />
                </div>
                <div>
                   <p className="text-[9px] font-black text-brand uppercase tracking-widest">{t.itemDiscussion}</p>
