import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, ArrowRight, ArrowLeft, Compass, MapPinned, Wallet } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [selectedCoin, setSelectedCoin] = useState('');
  const [payoutAddress, setPayoutAddress] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user.location || { address: '', lat: 0, lng: 0 });

  const cryptoCoins = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

  const handleAutoLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        const { latitude, longitude } = position.coords;
        const mockAddress = lang === 'ar' ? `موقع محدد (${latitude.toFixed(2)}, ${longitude.toFixed(2)})` : `Detected (${latitude.toFixed(2)}, ${longitude.toFixed(2)})`;
        setLocation({ address: mockAddress, lat: latitude, lng: longitude });
        setIsLocating(false);
      }, () => {
        alert(lang === 'ar' ? 'فشل تحديد الموقع.' : 'Location failed.');
        setIsLocating(false);
      });
    }
  };

  const handlePublish = async () => {
    if (!title || !description || !price || !payoutAddress) return;

    setLoading(true);
    try {
      const result = await checkListingContent(title, description);
      if (result.status === 'APPROVED') {
        const l: Listing = {
          id: 'l_' + Date.now(), 
          ownerId: user.id, 
          ownerName: user.fullName, 
          ownerUsername: user.username,
          ownerAvatar: user.avatar, 
          title, 
          description, 
          type: ListingType.RENT, 
          price: parseFloat(price),
          currency: 'USD', 
          currencyType, 
          payoutAddress: currencyType === CurrencyType.CRYPTO ? `${selectedCoin}: ${payoutAddress}` : payoutAddress, 
          category, 
          location,
          images, 
          video: video || undefined, 
          rentalPeriod: period, 
          createdAt: new Date().toISOString(),
          views: 0, 
          likes: 0, 
          rating: 0, 
          isAiApproved: true
        };
        onCreated(l);
        setStep(5);
      } else {
        alert(t.aiRejected + ": " + result.reason);
      }
    } catch (error) {
      alert(lang === 'ar' ? 'حدث خطأ أثناء النشر. حاول مرة أخرى.' : 'Error during publishing. Try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-900 rounded-[3rem] my-8 border dark:border-gray-800 shadow-sm animate-in fade-in slide-in-from-bottom-4">
      <div className="flex gap-1 mb-8">
        {[1,2,3,4,5].map(s => <div key={s} className={`h-1.5 flex-1 rounded-full ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />)}
      </div>

      {step === 1 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'وسائط المنتج' : 'Product Media'}</h2>
          <div className="grid grid-cols-3 gap-2">
            {images.map((img, i) => <img key={i} src={img} className="aspect-square object-cover rounded-2xl border dark:border-gray-700 shadow-sm" />)}
            {images.length < 5 && (
              <button 
                type="button"
                onClick={() => imageInputRef.current?.click()}
                className="aspect-square border-4 border-dashed border-gray-100 dark:border-gray-800 rounded-2xl flex flex-col items-center justify-center cursor-pointer text-gray-300 hover:border-brand hover:text-brand transition-all group"
              >
                <Camera size={32} className="group-hover:scale-110 transition-transform" />
                <span className="text-[8px] font-black uppercase mt-1">Add Photo</span>
                <input 
                  type="file" 
                  ref={imageInputRef}
                  multiple 
                  accept="image/*" 
                  className="hidden" 
                  onChange={e => {
                    if (e.target.files) {
                      const files = Array.from(e.target.files).map((f: File) => URL.createObjectURL(f));
                      setImages([...images, ...files].slice(0, 5));
                    }
                  }} 
                />
              </button>
            )}
          </div>
          <button 
            type="button"
            onClick={() => videoInputRef.current?.click()}
            className="w-full flex items-center justify-center gap-3 p-5 bg-gray-50 dark:bg-gray-800 border-2 border-dashed dark:border-gray-700 rounded-3xl dark:text-white cursor-pointer hover:bg-white hover:border-brand transition-all font-black text-xs uppercase"
          >
            <Video size={20} className="text-brand" /> {video ? (lang === 'ar' ? 'تم اختيار الفيديو ✅' : 'Video Selected ✅') : (lang === 'ar' ? 'رفع فيديو للمنتج' : 'Upload Product Video')}
            <input 
              type="file" 
              ref={videoInputRef}
              accept="video/*" 
              className="hidden" 
              onChange={e => {
                if (e.target.files && e.target.files[0]) {
                  setVideo(URL.createObjectURL(e.target.files[0]));
                }
              }} 
            />
          </button>
          <button disabled={images.length < 1} onClick={() => setStep(2)} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all disabled:opacity-30">
            {t.next}
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'تفاصيل الإعلان' : 'Listing Details'}</h2>
          <input type="text" placeholder={lang === 'ar' ? 'اسم المنتج*' : 'Product Name*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner" />
          <textarea placeholder={lang === 'ar' ? 'الوصف المكتوب*' : 'Detailed Description*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-32 outline-none font-bold shadow-inner" />
          <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold cursor-pointer">
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block px-2">{t.location}*</label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <MapPinned size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-brand" />
                <input 
                  type="text" 
                  placeholder={lang === 'ar' ? 'أدخل عنوان الغرض يدوياً...' : 'Enter item address...'} 
                  value={location.address} 
                  onChange={e => setLocation({...location, address: e.target.value})} 
                  className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-inner" 
                />
              </div>
              <button 
                type="button" 
                onClick={handleAutoLocation}
                className="p-4 bg-white dark:bg-gray-800 border-2 border-brand/20 text-brand rounded-2xl hover:bg-brand hover:text-white transition-all shadow-sm active:scale-90"
              >
                {isLocating ? <Loader2 size={24} className="animate-spin" /> : <Compass size={24} />}
              </button>
            </div>
          </div>

          <div className="flex gap-2">
             <button onClick={() => setStep(1)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-3xl font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button disabled={!title || !description || !location.address} onClick={() => setStep(3)} className="flex-[2] py-5 bg-brand text-white rounded-3xl font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all disabled:opacity-30">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{t.payoutMethod}*</h2>
          <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutAddress('')}} className={`flex-1 py-4 rounded-xl font-black uppercase tracking-widest text-[10px] transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutAddress('')}} className={`flex-1 py-4 rounded-xl font-black uppercase tracking-widest text-[10px] transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow' : 'text-gray-400'}`}>{t.local}</button>
          </div>

          {currencyType === CurrencyType.CRYPTO ? (
            <div className="space-y-4 animate-in slide-in-from-top-2">
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                {cryptoCoins.map(coin => (
                  <button key={coin} onClick={() => setSelectedCoin(coin)} className={`p-3 rounded-xl border-2 text-[9px] font-black uppercase tracking-widest transition-all ${selectedCoin === coin ? 'border-brand bg-brand/5 text-brand shadow-lg' : 'border-transparent bg-gray-50 dark:bg-gray-800 dark:text-white'}`}>{coin}</button>
                ))}
              </div>
              {selectedCoin && (
                <div className="relative group">
                  <Wallet size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-brand opacity-40 group-focus-within:opacity-100 transition-opacity" />
                  <input 
                    type="text" 
                    placeholder={lang === 'ar' ? `أدخل عنوان محفظة ${selectedCoin}*` : `Enter ${selectedCoin} Wallet Address*`} 
                    value={payoutAddress} 
                    onChange={e => setPayoutAddress(e.target.value)} 
                    className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" 
                  />
                </div>
              )}
            </div>
          ) : (
            <div className="relative group">
               <input 
                 type="email" 
                 placeholder={lang === 'ar' ? 'بريد PayPal لاستلام الأرباح*' : 'PayPal Email for Payouts*'} 
                 value={payoutAddress} 
                 onChange={e => setPayoutAddress(e.target.value)} 
                 className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" 
               />
            </div>
          )}

          <div className="flex gap-2 pt-4">
             <button onClick={() => setStep(2)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-3xl font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button disabled={!payoutAddress || (currencyType === CurrencyType.CRYPTO && !selectedCoin)} onClick={() => setStep(4)} className="flex-[2] py-5 bg-brand text-white rounded-3xl font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all disabled:opacity-30">{t.next}</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6">
          <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter italic">{lang === 'ar' ? 'تحديد السعر' : 'Pricing Policy'}</h2>
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <span className="absolute left-5 top-1/2 -translate-y-1/2 font-black text-brand text-xl">$</span>
              <input type="number" placeholder={lang === 'ar' ? 'السعر (USD)*' : 'Price (USD)*'} value={price} onChange={e => setPrice(e.target.value)} className="w-full pl-10 pr-4 py-5 rounded-[1.8rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black text-2xl shadow-inner focus:ring-2 focus:ring-brand" />
            </div>
            <select value={period} onChange={e => setPeriod(e.target.value as RentalPeriod)} className="p-5 rounded-[1.8rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black text-xs uppercase cursor-pointer border-2 border-transparent focus:border-brand">
              {Object.keys(RentalPeriod).map(p => <option key={p} value={p}>{t.periods[p]}</option>)}
            </select>
          </div>

          <div className="p-8 bg-brand/5 border border-brand/20 rounded-[2.5rem] text-center space-y-3">
             <div className="w-16 h-16 bg-white dark:bg-gray-900 rounded-[1.5rem] flex items-center justify-center mx-auto shadow-sm">
               <ShieldCheck size={32} className="text-brand animate-pulse" />
             </div>
             <div>
               <h3 className="font-black dark:text-white uppercase tracking-tighter">{t.aiChecking}</h3>
               <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest max-w-[240px] mx-auto leading-relaxed">AI my rents protocol scans every listing to prevent fraud and ensure item quality.</p>
             </div>
          </div>

          <div className="flex gap-2">
             <button onClick={() => setStep(3)} className="flex-1 py-5 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-3xl font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button onClick={handlePublish} disabled={loading || !price} className="flex-[2] py-5 bg-brand text-white rounded-3xl font-black shadow-xl shadow-brand/20 flex items-center justify-center gap-2 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
               {loading ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Publish Listing</>}
             </button>
          </div>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-12 space-y-8 animate-in zoom-in-95 duration-500">
          <div className="w-28 h-28 bg-green-500 text-white rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl shadow-green-500/30 rotate-3">
            <CheckCircle size={56} />
          </div>
          <div>
            <h2 className="text-5xl font-black dark:text-white uppercase tracking-tighter italic mb-2 leading-none">{t.aiApproved}</h2>
            <p className="text-gray-400 font-bold uppercase tracking-widest text-[10px] max-w-xs mx-auto">Your personal item is now live and protected by my rents security layer.</p>
          </div>
          <button onClick={() => navigate('/')} className="w-full py-6 bg-brand text-white rounded-[2rem] font-black shadow-xl shadow-brand/20 uppercase tracking-widest hover:scale-105 active:scale-95 transition-all">
            Return to Marketplace
          </button>
        </div>
      )}
    </div>
  );
};

