            <span className="text-[10px] font-black uppercase text-gray-400">{t.signupSteps.profilePic}</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input type="text" required placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-sm" />
            <input type="text" required placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-sm" />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest block px-2">{t.location}</label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <MapPinned size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-brand" />
                <input 
                  type="text" 
                  required 
                  readOnly
                  placeholder={lang === 'ar' ? 'اضغط لتحديد الدولة والمدينة...' : 'Tap to fetch structured address...'} 
                  value={signupData.location.address} 
                  className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-sm" 
                />
              </div>
              <button 
                type="button" 
                onClick={handleAutoLocation}
                className="p-4 bg-white dark:bg-gray-800 border-2 border-brand/20 text-brand rounded-2xl hover:bg-brand hover:text-white transition-all shadow-sm active:scale-90"
              >
                {isLocating ? <Loader2 size={24} className="animate-spin" /> : <MapPin size={24} />}
              </button>
            </div>
          </div>

          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-start gap-3 border dark:border-gray-700 shadow-inner">
             <input 
                type="checkbox" 
                id="agreed" 
                required 
                checked={signupData.agreed} 
                onChange={e => setSignupData({...signupData, agreed: e.target.checked})} 
                className="mt-1 w-5 h-5 accent-brand rounded cursor-pointer"
             />
             <label htmlFor="agreed" className="text-[11px] font-bold dark:text-white leading-relaxed cursor-pointer">
                {lang === 'ar' ? (
                  <>أوافق على <Link to="/privacy" className="text-brand underline">سياسة الخصوصية</Link> و <Link to="/terms" className="text-brand underline">شروط الاستخدام</Link></>
                ) : (
                  <>I agree to <Link to="/privacy" className="text-brand underline">Privacy Policy</Link> and <Link to="/terms" className="text-brand underline">Terms</Link></>
                )}
             </label>
          </div>

          <button type="submit" disabled={!signupData.fullName || !signupData.agreed} className="w-full py-5 bg-brand text-white rounded-[2.5rem] font-black shadow-xl shadow-brand/20 tracking-widest uppercase hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-30">
            {lang === 'ar' ? 'ابدأ رحلة الإيجار' : 'Get Started'}
          </button>
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}
        <main className={user ? 'pb-20' : ''}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={allListings.filter(l => l.ownerId === user.id)} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            {user && (
              <>
                <Route path="/discovery" element={
                  <div className="p-8 animate-in fade-in">
                    <div className="text-center mb-12">
                      <Compass size={64} className="mx-auto text-brand mb-4 animate-spin-slow" />
                      <h1 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-2 italic">{t.discovery}</h1>
                      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">{lang === 'ar' ? 'استكشف ما هو متاح بالقرب منك' : 'Explore what is available nearby'}</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 max-w-7xl mx-auto">
                      {allListings.length === 0 ? (
                         <div className="col-span-full py-20 text-center opacity-20">
                            <Box size={64} className="mx-auto mb-4" />
                            <p className="font-black uppercase tracking-widest text-sm">No items in your area yet</p>
                         </div>
                      ) : allListings.map(l => <ListingCard key={l.id} listing={l} lang={lang} isOwner={l.ownerId === user.id} onDelete={(id) => setAllListings(prev => prev.filter(item => item.id !== id))} onAddPoints={addPoints} />)}
                    </div>
                  </div>
                } />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => { setAllListings(prev => [...prev, l]); addPoints(POINTS_SYSTEM.CREATE_LISTING); }} />} />
                <Route path="/chat/*" element={<ChatPage lang={lang} onAddPoints={addPoints} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
              </>
            )}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, ArrowRight, ArrowLeft, Compass, MapPinned, Wallet, Award, Sparkles } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [selectedCoin, setSelectedCoin] = useState('');
  const [payoutAddress, setPayoutAddress] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user.location || { address: '', lat: 0, lng: 0 });

  const cryptoCoins = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

  const handleAutoLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          // Real reverse geocoding using OpenStreetMap (No key required for prototype)
          const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&addressdetails=1&accept-language=${lang}`);
          const data = await response.json();
          const { address } = data;

          const country = address.country || '';
          const city = address.city || address.town || address.village || address.state || '';
          const neighborhood = address.suburb || address.neighbourhood || address.residential || address.road || '';

          const fullAddress = [country, city, neighborhood].filter(Boolean).join(', ');
          setLocation({ address: fullAddress, lat: latitude, lng: longitude });
        } catch (e) {
          setLocation({ address: `${latitude.toFixed(2)}, ${longitude.toFixed(2)}`, lat: latitude, lng: longitude });
        } finally {
          setIsLocating(false);
        }
      }, () => {
        alert(lang === 'ar' ? 'فشل تحديد الموقع. يرجى تفعيل GPS.' : 'Location failed. Please enable GPS.');
        setIsLocating(false);
      });
    }
  };

  const handlePublish = async () => {
    if (!title || !description || !price || !payoutAddress) return;

    setLoading(true);
    try {
      const result = await checkListingContent(title, description);
      if (result.status === 'APPROVED') {
        const l: Listing = {
          id: 'l_' + Date.now(), 
          ownerId: user.id, 
          ownerName: user.fullName, 
          ownerUsername: user.username,
          ownerAvatar: user.avatar, 
          title, 
          description, 
          type: ListingType.RENT, 
          price: parseFloat(price),
          currency: 'USD', 
          currencyType, 
          payoutAddress: currencyType === CurrencyType.CRYPTO ? `${selectedCoin}: ${payoutAddress}` : payoutAddress, 
          category, 
          location,
          images, 
          video: video || undefined, 
          rentalPeriod: period, 
          createdAt: new Date().toISOString(),
          views: 0, 
          likes: 0, 
          rating: 0, 
          isAiApproved: true
        };
        onCreated(l);
        setTimeout(() => setStep(5), 1500); // Visual delay for elegance
      } else {
        alert(t.aiRejected + ": " + result.reason);
      }
    } catch (error) {
      alert(lang === 'ar' ? 'حدث خطأ أثناء النشر. حاول مرة أخرى.' : 'Error during publishing. Try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-8 bg-white dark:bg-gray-900 rounded-[4rem] my-8 border dark:border-gray-800 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="flex gap-2 mb-12">
        {[1,2,3,4,5].map(s => (
          <div key={s} className="flex-1">
            <div className={`h-2 rounded-full transition-all duration-500 ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />
            <span className={`text-[8px] font-black uppercase tracking-widest mt-2 block text-center ${step === s ? 'text-brand' : 'text-gray-300'}`}>Step {s}</span>
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in slide-in-from-right duration-300">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{lang === 'ar' ? 'عرض الوسائط' : 'Media Showcase'}</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-2">Upload high-quality photos and video to rent faster</p>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
            {images.map((img, i) => (
              <div key={i} className="group relative aspect-square overflow-hidden rounded-[1.8rem] border-2 border-brand/10 shadow-lg">
                <img src={img} className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                <button onClick={() => setImages(images.filter((_, idx) => idx !== i))} className="absolute top-2 right-2 p-1.5 bg-brand text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                   <Award size={10} className="rotate-45" />
                </button>
              </div>
            ))}
            {images.length < 5 && (
              <button 
                type="button"
                onClick={() => imageInputRef.current?.click()}
                className="aspect-square bg-gray-50 dark:bg-gray-800 rounded-[1.8rem] border-4 border-dashed border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center cursor-pointer text-gray-300 hover:border-brand hover:text-brand hover:bg-white transition-all group"
              >
                <Camera size={32} className="group-hover:scale-110 transition-transform mb-1" />
                <span className="text-[8px] font-black uppercase tracking-tighter">Add Photo</span>
                {/* Fixed potential type error by explicitly handling File objects from file inputs */}
                <input type="file" ref={imageInputRef} multiple accept="image/*" className="hidden" onChange={e => {
                  if (e.target.files) {
                    const newImages = Array.from(e.target.files).map(f => URL.createObjectURL(f));
                    setImages([...images, ...newImages].slice(0, 5));
                  }
                }} />
              </button>
            )}
          </div>

          <button 
            type="button"
            onClick={() => videoInputRef.current?.click()}
            className={`w-full p-8 rounded-[2.5rem] border-2 border-dashed transition-all flex items-center justify-center gap-4 ${video ? 'bg-brand/5 border-brand text-brand' : 'bg-gray-50 dark:bg-gray-800 border-gray-100 dark:border-gray-700 text-gray-400 hover:border-brand/30'}`}
          >
            <Video size={28} />
            <div className="text-left">
              <span className="block font-black uppercase text-xs tracking-tighter">{video ? (lang === 'ar' ? 'تم توثيق الفيديو' : 'Video Authenticated') : (lang === 'ar' ? 'رفع فيديو عالي الجودة' : 'Upload Cinema Video')}</span>
              <span className="text-[9px] font-bold opacity-60 uppercase">{video ? 'Ready for AI scanning' : 'Max 60 seconds - MP4 supported'}</span>
            </div>
            {/* Fixed type error by ensuring a File is present before calling URL.createObjectURL */}
            <input type="file" ref={videoInputRef} accept="video/*" className="hidden" onChange={e => {
              const file = e.target.files?.[0];
              if (file) {
                setVideo(URL.createObjectURL(file));
              }
            }} />
          </button>

          <button disabled={images.length < 1} onClick={() => setStep(2)} className="w-full py-6 bg-brand text-white rounded-[2.2rem] font-black uppercase tracking-widest shadow-2xl shadow-brand/30 active:scale-95 transition-all disabled:opacity-20">
            {t.next}
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-8 animate-in slide-in-from-right duration-300">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{lang === 'ar' ? 'هوية الغرض' : 'Item Identity'}</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-2">Define your item with clarity and location precision</p>
          </div>

          <div className="space-y-4">
            <input type="text" placeholder={lang === 'ar' ? 'اسم المنتج*' : 'Product Name*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-6 rounded-[1.8rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black text-lg focus:ring-2 focus:ring-brand shadow-inner" />
            <textarea placeholder={lang === 'ar' ? 'الوصف التفصيلي*' : 'Detailed Description*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-6 rounded-[1.8rem] bg-gray-50 dark:bg-gray-800 dark:text-white h-40 outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-5 rounded-[1.8rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black uppercase text-xs border-r-8 border-transparent cursor-pointer">
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>

              <div className="relative group">
                 <button 
                  type="button" 
                  onClick={handleAutoLocation}
                  disabled={isLocating}
                  className="w-full p-5 bg-brand text-white rounded-[1.8rem] flex items-center justify-center gap-3 font-black uppercase text-[10px] tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all"
                >
                  {isLocating ? <Loader2 className="animate-spin" size={16} /> : <Compass size={16} />}
                  {lang === 'ar' ? 'تحديد الموقع الذكي' : 'Smart Geolocation'}
                </button>
              </div>
            </div>

            <div className="p-6 bg-brand/5 border border-brand/20 rounded-[2rem] flex items-center gap-4">
               <div className="w-12 h-12 bg-white dark:bg-gray-800 rounded-2xl flex items-center justify-center text-brand shadow-sm">
                  <MapPinned size={24} />
               </div>
               <div className="flex-1">
                  <span className="text-[9px] font-black text-brand uppercase tracking-widest block">{t.location}</span>
                  <input 
                    type="text" 
                    value={location.address} 
                    readOnly 
                    placeholder={lang === 'ar' ? 'جاري تحديد الحي والمدينة...' : 'Waiting for neighborhood/city...'}
                    className="w-full bg-transparent outline-none font-black dark:text-white text-xs" 
                  />
               </div>
            </div>
          </div>

          <div className="flex gap-4">
             <button onClick={() => setStep(1)} className="flex-1 py-6 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2.2rem] font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button disabled={!title || !description || !location.address} onClick={() => setStep(3)} className="flex-[2] py-6 bg-brand text-white rounded-[2.2rem] font-black uppercase tracking-widest shadow-2xl shadow-brand/30 active:scale-95 transition-all disabled:opacity-30">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in slide-in-from-right duration-300">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{t.payoutMethod}</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-2">Choose how you want to receive your rental earnings</p>
          </div>

          <div className="flex p-2 bg-gray-100 dark:bg-gray-800 rounded-[2.5rem] gap-2">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutAddress('')}} className={`flex-1 py-5 rounded-[2rem] font-black uppercase tracking-widest text-xs transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-xl' : 'text-gray-400'}`}>{t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutAddress('')}} className={`flex-1 py-5 rounded-[2rem] font-black uppercase tracking-widest text-xs transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-xl' : 'text-gray-400'}`}>{t.local}</button>
          </div>

          {currencyType === CurrencyType.CRYPTO ? (
            <div className="space-y-6 animate-in zoom-in-95">
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                {cryptoCoins.map(coin => (
                  <button key={coin} onClick={() => setSelectedCoin(coin)} className={`p-4 rounded-2xl border-2 text-[10px] font-black uppercase transition-all ${selectedCoin === coin ? 'border-brand bg-brand/5 text-brand shadow-lg' : 'border-transparent bg-gray-50 dark:bg-gray-800 dark:text-white'}`}>{coin}</button>
                ))}
              </div>
              {selectedCoin && (
                <div className="relative group">
                  <Wallet size={20} className="absolute left-6 top-1/2 -translate-y-1/2 text-brand opacity-40 group-focus-within:opacity-100" />
                  <input type="text" placeholder={lang === 'ar' ? `عنوان محفظة ${selectedCoin}*` : `${selectedCoin} Wallet Address*`} value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} className="w-full pl-16 pr-6 py-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" />
                </div>
              )}
            </div>
          ) : (
            <input type="email" placeholder={lang === 'ar' ? 'بريد PayPal الخاص بك*' : 'Your PayPal Payout Email*'} value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} className="w-full p-6 rounded-[2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" />
          )}

          <div className="flex gap-4">
             <button onClick={() => setStep(2)} className="flex-1 py-6 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2.2rem] font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button disabled={!payoutAddress || (currencyType === CurrencyType.CRYPTO && !selectedCoin)} onClick={() => setStep(4)} className="flex-[2] py-6 bg-brand text-white rounded-[2.2rem] font-black uppercase tracking-widest shadow-2xl shadow-brand/30 active:scale-95 transition-all disabled:opacity-30">{t.next}</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 animate-in slide-in-from-right duration-300">
          <div className="text-center">
            <h2 className="text-3xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{t.finalizeAndSeal}</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-2">Verify details and apply the secure digital signature</p>
          </div>

          <div className="bg-gray-50 dark:bg-gray-800 rounded-[3rem] p-8 border dark:border-gray-700 relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
               <Award size={120} />
            </div>
            <div className="relative z-10 flex flex-col items-center">
              <div className="flex items-baseline gap-2 mb-6">
                <span className="text-5xl font-black text-brand">${price || '0'}</span>
                <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">USD / {t.periods[period]}</span>
              </div>
              <div className="grid grid-cols-2 gap-8 w-full">
                <div className="text-center border-r dark:border-gray-700">
                  <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Security Scan</p>
                  <p className="text-xs font-black text-green-500 uppercase flex items-center justify-center gap-1"><CheckCircle size={12} /> Ready</p>
                </div>
                <div className="text-center">
                  <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Location Tier</p>
                  <p className="text-xs font-black dark:text-white uppercase">{location.address.split(',')[0] || 'Local'}</p>
                </div>
              </div>
            </div>
          </div>

          <div className="space-y-4">
             <div className="relative group">
                <input type="number" placeholder={lang === 'ar' ? 'تعديل السعر النهائي*' : 'Set Final Price (USD)*'} value={price} onChange={e => setPrice(e.target.value)} className="w-full p-6 rounded-[2rem] bg-gray-100 dark:bg-gray-700 dark:text-white outline-none font-black text-2xl text-center focus:ring-2 focus:ring-brand shadow-inner" />
             </div>
             <div className="flex items-center justify-center gap-2 p-4 bg-brand/5 border border-dashed border-brand/20 rounded-2xl">
                <ShieldCheck size={18} className="text-brand" />
                <span className="text-[10px] font-black uppercase text-brand tracking-widest">AI Safety Protocol Engaged</span>
             </div>
          </div>

          <div className="flex gap-4">
             <button onClick={() => setStep(3)} className="flex-1 py-6 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2.2rem] font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button 
              onClick={handlePublish} 
              disabled={loading || !price} 
              className="flex-[3] py-8 bg-brand text-white rounded-[2.5rem] font-black text-lg uppercase tracking-widest shadow-[0_20px_60px_-15px_rgba(255,0,0,0.3)] hover:shadow-brand/50 hover:-translate-y-1 active:scale-95 transition-all flex items-center justify-center gap-4 group disabled:opacity-50 overflow-hidden relative"
             >
