                     if (e.target.files && e.target.files.length > 0) {
                       setGroupData({...groupData, image: URL.createObjectURL(e.target.files[0])});
                     }
                   }} />
                 </button>
                 <input type="text" placeholder={lang === 'ar' ? 'اسم المجتمع*' : 'Community Name*'} value={groupData.name} onChange={e => setGroupData({...groupData, name: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-sm" />
                 <textarea placeholder={lang === 'ar' ? 'وصف المجتمع*' : 'Description*'} value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-24 outline-none font-bold shadow-sm" />
                 <button onClick={() => { alert(lang === 'ar' ? 'تم إنشاء المجموعة!' : 'Community created!'); setShowGroupCreate(false); }} disabled={!groupData.name || !groupData.image} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all">Launch Community</button>
                 <button onClick={() => setShowGroupCreate(false)} className="w-full py-2 text-gray-400 font-black text-[10px] uppercase tracking-widest">{t.back}</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default ChatPage;

import React, { useState, useRef } from 'react';
import { translations } from '../i18n';
import { CATEGORIES } from '../constants';
import { CurrencyType, RentalPeriod, ListingType, Listing } from '../types';
import { checkListingContent } from '../services/geminiService';
import { Camera, Video, MapPin, Loader2, CheckCircle, ShieldCheck, ArrowRight, ArrowLeft, Compass, MapPinned, Wallet, Award, Sparkles, ShieldAlert } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CreateListingPage: React.FC<{ lang: string; user: any; onCreated: (l: Listing) => void }> = ({ lang, user, onCreated }) => {
  const t = translations[lang] || translations['en'];
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [isLocating, setIsLocating] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const [images, setImages] = useState<string[]>([]);
  const [video, setVideo] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [currencyType, setCurrencyType] = useState<CurrencyType>(CurrencyType.LOCAL);
  const [selectedCoin, setSelectedCoin] = useState('');
  const [payoutAddress, setPayoutAddress] = useState('');
  const [price, setPrice] = useState('');
  const [period, setPeriod] = useState<RentalPeriod>(RentalPeriod.DAY);
  const [location, setLocation] = useState(user.location || { address: '', lat: 0, lng: 0 });

  const cryptoCoins = ['Solana', 'Ethereum', 'Monad', 'Base', 'Sui', 'Polygon', 'Bitcoin'];

  const handleAutoLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&addressdetails=1&accept-language=${lang}`);
          const data = await response.json();
          const { address } = data;

          const country = address.country || '';
          const city = address.city || address.town || address.village || address.state || '';
          const neighborhood = address.suburb || address.neighbourhood || address.residential || address.road || '';

          const fullAddress = [country, city, neighborhood].filter(Boolean).join(', ');
          setLocation({ address: fullAddress, lat: latitude, lng: longitude });
        } catch (e) {
          setLocation({ address: `${latitude.toFixed(2)}, ${longitude.toFixed(2)}`, lat: latitude, lng: longitude });
        } finally {
          setIsLocating(false);
        }
      }, () => {
        alert(lang === 'ar' ? 'فشل تحديد الموقع. يرجى تفعيل GPS.' : 'Location failed. Please enable GPS.');
        setIsLocating(false);
      });
    }
  };

  const handlePublish = async () => {
    if (!title || !description || !price || !payoutAddress) return;

    setLoading(true);
    try {
      const result = await checkListingContent(title, description);
      if (result.status === 'APPROVED') {
        const l: Listing = {
          id: 'l_' + Date.now(), 
          ownerId: user.id, 
          ownerName: user.fullName, 
          ownerUsername: user.username,
          ownerAvatar: user.avatar, 
          title, 
          description, 
          type: ListingType.RENT, 
          price: parseFloat(price),
          currency: 'USD', 
          currencyType, 
          payoutAddress: currencyType === CurrencyType.CRYPTO ? `${selectedCoin}: ${payoutAddress}` : payoutAddress, 
          category, 
          location,
          images, 
          video: video || undefined, 
          rentalPeriod: period, 
          createdAt: new Date().toISOString(),
          views: 0, 
          likes: 0, 
          rating: 0, 
          isAiApproved: true
        };
        onCreated(l);
        setTimeout(() => setStep(5), 1800); 
      } else {
        alert(t.aiRejected + ": " + result.reason);
      }
    } catch (error) {
      alert(lang === 'ar' ? 'حدث خطأ أثناء النشر. حاول مرة أخرى.' : 'Error during publishing. Try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-10 bg-white dark:bg-gray-900 rounded-[4.5rem] my-10 border dark:border-gray-800 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.1)] animate-in fade-in slide-in-from-bottom-12 duration-1000">
      <div className="flex gap-3 mb-16">
        {[1,2,3,4,5].map(s => (
          <div key={s} className="flex-1">
            <div className={`h-2.5 rounded-full transition-all duration-700 ${step >= s ? 'bg-brand' : 'bg-gray-100 dark:bg-gray-800'}`} />
            <span className={`text-[9px] font-black uppercase tracking-[0.2em] mt-3 block text-center ${step === s ? 'text-brand' : 'text-gray-300 dark:text-gray-600'}`}>{lang === 'ar' ? `المرحلة ${s}` : `Phase ${s}`}</span>
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="space-y-10 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{lang === 'ar' ? 'المعرض المرئي' : 'Media Showcase'}</h2>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-4">Upload high-fidelity photos and premium video content</p>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-5 gap-4">
            {images.map((img, i) => (
              <div key={i} className="group relative aspect-square overflow-hidden rounded-[2.2rem] border-2 border-brand/5 shadow-2xl hover:scale-105 transition-all">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => setImages(images.filter((_, idx) => idx !== i))} className="absolute top-3 right-3 p-2 bg-brand text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                   <Award size={12} className="rotate-45" />
                </button>
              </div>
            ))}
            {images.length < 5 && (
              <button 
                type="button"
                onClick={() => imageInputRef.current?.click()}
                className="aspect-square bg-gray-50/50 dark:bg-gray-800/50 rounded-[2.2rem] border-4 border-dashed border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center cursor-pointer text-gray-300 hover:border-brand hover:text-brand hover:bg-white dark:hover:bg-gray-800 transition-all group"
              >
                <Camera size={36} className="group-hover:scale-110 transition-transform mb-2" />
                <span className="text-[9px] font-black uppercase tracking-tighter">Capture</span>
                <input type="file" ref={imageInputRef} multiple accept="image/*" className="hidden" onChange={e => {
                  /* Added type casting for EventTarget to HTMLInputElement to fix unknown type error on files */
                  const target = e.target as HTMLInputElement;
                  if (target.files && target.files.length > 0) {
                    const newImages = Array.from(target.files).map(f => URL.createObjectURL(f));
                    setImages([...images, ...newImages].slice(0, 5));
                  }
                }} />
              </button>
            )}
          </div>

          <button 
            type="button"
            onClick={() => videoInputRef.current?.click()}
            className={`w-full p-10 rounded-[3rem] border-2 border-dashed transition-all flex items-center justify-center gap-6 ${video ? 'bg-brand/5 border-brand text-brand' : 'bg-gray-50 dark:bg-gray-800 border-gray-100 dark:border-gray-700 text-gray-400 hover:border-brand/40'}`}
          >
            <div className={`p-5 rounded-3xl ${video ? 'bg-brand text-white' : 'bg-gray-100 dark:bg-gray-700'}`}>
               <Video size={32} />
            </div>
            <div className="text-left">
              <span className="block font-black uppercase text-sm tracking-tighter">{video ? (lang === 'ar' ? 'تمت أرشفة الفيديو' : 'Video Archived') : (lang === 'ar' ? 'تسجيل مقطع تعريفي' : 'Record Identity Video')}</span>
              <span className="text-[10px] font-bold opacity-60 uppercase tracking-widest">{video ? 'Identity Verified' : 'Standard MP4/MOV - Up to 20MB'}</span>
            </div>
            <input type="file" ref={videoInputRef} accept="video/*" className="hidden" onChange={e => {
              /* Added type casting for EventTarget to HTMLInputElement to fix unknown type error on files */
              const target = e.target as HTMLInputElement;
              const file = target.files?.[0];
              if (file) {
                setVideo(URL.createObjectURL(file));
              }
            }} />
          </button>

          <button disabled={images.length < 1} onClick={() => setStep(2)} className="w-full py-8 bg-brand text-white rounded-[2.8rem] font-black uppercase tracking-[0.2em] shadow-[0_25px_60px_-15px_rgba(255,0,0,0.3)] active:scale-95 transition-all disabled:opacity-10">
            {t.next}
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-10 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{lang === 'ar' ? 'هوية المنتج' : 'Item Signature'}</h2>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-4">Precision is key for high-end rental matches</p>
          </div>

          <div className="space-y-5">
            <input type="text" placeholder={lang === 'ar' ? 'عنوان الإعلان البارز*' : 'Headline Title*'} value={title} onChange={e => setTitle(e.target.value)} className="w-full p-7 rounded-[2.2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black text-xl focus:ring-2 focus:ring-brand shadow-inner" />
            <textarea placeholder={lang === 'ar' ? 'وصف تفصيلي شامل*' : 'In-depth Description*'} value={description} onChange={e => setDescription(e.target.value)} className="w-full p-7 rounded-[2.2rem] bg-gray-50 dark:bg-gray-800 dark:text-white h-48 outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <select value={category} onChange={e => setCategory(e.target.value)} className="w-full p-6 rounded-[2.2rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-black uppercase text-xs border-r-[20px] border-transparent cursor-pointer appearance-none">
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>

              <button 
                type="button" 
                onClick={handleAutoLocation}
                disabled={isLocating}
                className="w-full p-6 bg-brand text-white rounded-[2.2rem] flex items-center justify-center gap-4 font-black uppercase text-xs tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all"
              >
                {isLocating ? <Loader2 className="animate-spin" size={18} /> : <Compass size={18} />}
                {lang === 'ar' ? 'تحديد العنوان الذكي' : 'Fetch Smart Address'}
              </button>
            </div>

            <div className="p-8 bg-brand/5 border-2 border-brand/10 rounded-[3rem] flex items-center gap-6 group">
               <div className="w-16 h-16 bg-white dark:bg-gray-800 rounded-3xl flex items-center justify-center text-brand shadow-xl transition-transform group-hover:scale-110">
                  <MapPinned size={32} />
               </div>
               <div className="flex-1">
                  <span className="text-[10px] font-black text-brand uppercase tracking-[0.2em] block mb-1">{t.location}</span>
                  <input 
                    type="text" 
                    value={location.address} 
                    readOnly 
                    placeholder={lang === 'ar' ? 'اضغط لتحديد الدولة والمدينة والحي...' : 'Waiting for country/city/neighborhood...'}
                    className="w-full bg-transparent outline-none font-black dark:text-white text-sm" 
                  />
               </div>
            </div>
          </div>

          <div className="flex gap-4 pt-4">
             <button onClick={() => setStep(1)} className="flex-1 py-7 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2.5rem] font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button disabled={!title || !description || !location.address} onClick={() => setStep(3)} className="flex-[2] py-7 bg-brand text-white rounded-[2.5rem] font-black uppercase tracking-widest shadow-2xl shadow-brand/30 active:scale-95 transition-all disabled:opacity-10">{t.next}</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-10 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{t.payoutMethod}</h2>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-4">Revenue stream configuration for instant earnings</p>
          </div>

          <div className="flex p-3 bg-gray-100 dark:bg-gray-800 rounded-[3.5rem] gap-3">
            <button onClick={() => {setCurrencyType(CurrencyType.CRYPTO); setPayoutAddress('')}} className={`flex-1 py-6 rounded-[3rem] font-black uppercase tracking-widest text-xs transition-all ${currencyType === CurrencyType.CRYPTO ? 'bg-white dark:bg-gray-900 text-brand shadow-2xl' : 'text-gray-400'}`}>{t.crypto}</button>
            <button onClick={() => {setCurrencyType(CurrencyType.LOCAL); setPayoutAddress('')}} className={`flex-1 py-6 rounded-[3rem] font-black uppercase tracking-widest text-xs transition-all ${currencyType === CurrencyType.LOCAL ? 'bg-white dark:bg-gray-900 text-brand shadow-2xl' : 'text-gray-400'}`}>{t.local}</button>
          </div>

          {currencyType === CurrencyType.CRYPTO ? (
            <div className="space-y-8 animate-in zoom-in-95">
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                {cryptoCoins.map(coin => (
                  <button key={coin} onClick={() => setSelectedCoin(coin)} className={`p-5 rounded-3xl border-2 text-[11px] font-black uppercase tracking-wider transition-all ${selectedCoin === coin ? 'border-brand bg-brand/5 text-brand shadow-xl' : 'border-transparent bg-gray-50 dark:bg-gray-800 dark:text-white'}`}>{coin}</button>
                ))}
              </div>
              {selectedCoin && (
                <div className="relative group">
                  <Wallet size={24} className="absolute left-8 top-1/2 -translate-y-1/2 text-brand opacity-40 group-focus-within:opacity-100 transition-opacity" />
                  <input type="text" placeholder={lang === 'ar' ? `عنوان محفظة ${selectedCoin} المعتمد*` : `Verified ${selectedCoin} Address*`} value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} className="w-full pl-20 pr-8 py-7 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand" />
                </div>
              )}
            </div>
          ) : (
            <div className="relative group">
              <input type="email" placeholder={lang === 'ar' ? 'بريد PayPal لاستلام المستحقات*' : 'Payout PayPal Email*'} value={payoutAddress} onChange={e => setPayoutAddress(e.target.value)} className="w-full p-7 rounded-[2.5rem] bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-inner focus:ring-2 focus:ring-brand text-center" />
            </div>
          )}

          <div className="flex gap-4">
             <button onClick={() => setStep(2)} className="flex-1 py-7 bg-gray-100 dark:bg-gray-800 text-gray-400 rounded-[2.5rem] font-black uppercase tracking-widest transition-all">{t.back}</button>
             <button disabled={!payoutAddress || (currencyType === CurrencyType.CRYPTO && !selectedCoin)} onClick={() => setStep(4)} className="flex-[2] py-7 bg-brand text-white rounded-[2.5rem] font-black uppercase tracking-widest shadow-2xl shadow-brand/30 active:scale-95 transition-all disabled:opacity-10">{t.next}</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-12 animate-in slide-in-from-right duration-500">
          <div className="text-center">
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{t.finalizeAndSeal}</h2>
            <p className="text-[11px] text-gray-400 font-bold uppercase tracking-widest mt-4">Apply the AI cryptographical seal to your listing</p>
          </div>

          <div className="relative p-1 bg-gradient-to-br from-brand via-brand/50 to-brand/20 rounded-[4rem] shadow-2xl group">
             <div className="bg-white dark:bg-gray-900 rounded-[3.8rem] p-10 flex flex-col items-center">
                <div className="w-24 h-24 bg-brand/10 text-brand rounded-[2rem] flex items-center justify-center mb-8 shadow-inner animate-pulse">
                   <ShieldCheck size={48} />
                </div>

                <div className="flex items-baseline gap-2 mb-10">
                  <span className="text-6xl font-black text-brand tracking-tighter">${price || '0'}</span>
                  <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">USD / {t.periods[period]}</span>
                </div>

                <div className="grid grid-cols-2 gap-10 w-full px-4 mb-4">
                  <div className="text-center border-r dark:border-gray-800">
                    <p className="text-[10px] font-black text-gray-300 uppercase tracking-[0.2em] mb-2">Policy Scan</p>
                    <p className="text-sm font-black text-green-500 uppercase flex items-center justify-center gap-2"><CheckCircle size={14} /> Passed</p>
                  </div>
                  <div className="text-center">
                    <p className="text-[10px] font-black text-gray-300 uppercase tracking-[0.2em] mb-2">Location Tier</p>
                    <p className="text-sm font-black dark:text-white uppercase truncate px-2">{location.address.split(',')[1] || 'Global'}</p>
                  </div>
                </div>
             </div>
          </div>

          <div className="space-y-6">
             <div className="relative group max-w-xs mx-auto">
                <input type="number" placeholder="0.00" value={price} onChange={e => setPrice(e.target.value)} className="w-full bg-transparent border-b-4 border-gray-100 dark:border-gray-800 dark:text-white text-5xl font-black text-center outline-none focus:border-brand transition-colors pb-4" />
                <p className="text-center mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Confirm Rental Rate (USD)</p>
             </div>
          </div>

          <div className="flex flex-col gap-4">
             <button 
              onClick={handlePublish} 
              disabled={loading || !price} 
              className="group relative w-full py-10 bg-brand text-white rounded-[3.5rem] font-black text-2xl uppercase tracking-[0.3em] shadow-[0_30px_80px_-20px_rgba(255,0,0,0.4)] hover:shadow-brand/60 hover:-translate-y-2 active:scale-95 transition-all overflow-hidden"
             >
                <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-700 ease-out" />
                <div className="relative z-10 flex items-center justify-center gap-6">
                  {loading ? (
                    <div className="flex items-center gap-4">
                      <Loader2 className="animate-spin" size={32} />
                      <span className="text-lg">SEALING...</span>
                    </div>
                  ) : (
                    <>
                      <Sparkles size={32} className="animate-pulse" />
                      {t.securePublish}
                      <Award size={32} />
                    </>
                  )}
                </div>
             </button>
             <button onClick={() => setStep(3)} className="py-4 text-gray-400 font-black text-[11px] uppercase tracking-[0.4em] hover:text-brand transition-colors">{t.back}</button>
          </div>
        </div>
      )}

      {step === 5 && (
        <div className="text-center py-20 space-y-12 animate-in zoom-in-95 duration-1000">
          <div className="relative inline-block">
            <div className="w-40 h-40 bg-green-500 text-white rounded-[4rem] flex items-center justify-center mx-auto shadow-[0_40px_100px_-20px_rgba(34,197,94,0.4)] rotate-3 animate-bounce">
              <CheckCircle size={80} />
            </div>
            <div className="absolute -top-6 -right-6 w-16 h-16 bg-yellow-400 text-white rounded-3xl flex items-center justify-center shadow-2xl rotate-12">
               <Award size={32} />
            </div>
          </div>
          <div className="space-y-4">
            <h2 className="text-7xl font-black dark:text-white uppercase tracking-tighter italic leading-none">{t.aiApproved}</h2>
            <p className="text-gray-400 font-bold uppercase tracking-widest text-sm max-w-md mx-auto leading-loose">The secure rental protocol is active. Your item is now discoverable across the verified my rents network.</p>
          </div>
          <button onClick={() => navigate('/')} className="w-full py-10 bg-brand text-white rounded-[3.5rem] font-black shadow-[0_30px_80px_-20px_rgba(255,0,0,0.3)] uppercase tracking-[0.3em] text-lg hover:scale-[1.03] active:scale-95 transition-all">
            Return to Market
          </button>
        </div>
      )}
    </div>
  );
};

export default CreateListingPage;

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useParams } from 'react-router-dom';
import { User, Gender, Listing } from './types';
import Navbar from './components/Navbar';
import ListingCard from './components/ListingCard';
import HomePage from './pages/HomePage';
import ItemDetailPage from './pages/ItemDetailPage';
import CreateListingPage from './pages/CreateListingPage';
import ChatPage from './pages/ChatPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfUsePage from './pages/TermsOfUsePage';
import SubscriptionPage from './pages/SubscriptionPage';
import { translations } from './i18n';
import { POINTS_SYSTEM } from './constants';
import { Camera, MapPinned, Compass, Box, Star, ChevronRight, User as UserIcon, Coins, Sparkles, Loader2, ChevronLeft, ShieldCheck, MapPin } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<string>('ar');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [allListings, setAllListings] = useState<Listing[]>([]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const t = translations[lang] || translations['en'];

  const addPoints = (amount: number) => {
    if (user) {
      setUser(prev => prev ? { ...prev, points: prev.points + amount } : null);
    }
  };

  const handleSignUpFinish = (e: React.FormEvent, data: any) => {
    e.preventDefault();
    const newUser: User = {
      id: 'u_' + Date.now(),
      fullName: data.fullName,
      username: data.username,
      email: data.email,
      avatar: data.avatar,
      gender: Gender.OTHER,
      birthDate: '2000-01-01',
      location: data.location,
      status: 'Member',
      points: 0, 
      listingsCount: 0,
      walletBalance: 0,
      payoutMethods: {},
      blockedUsers: []
    };
    setUser(newUser);
  };

  const ProfileView = () => {
    const { username } = useParams<{ username?: string }>();
    const isSelf = !username || (user && username === user.username);
    const displayUser = isSelf ? user : null; 

    const userSpecificListings = allListings.filter(l => l.ownerUsername === (username || user?.username));

    return (
      <div className="p-8 text-center max-w-4xl mx-auto animate-in fade-in">
        <div className="bg-white dark:bg-gray-900 rounded-[3.5rem] p-10 shadow-sm border dark:border-gray-800">
          <div className="relative inline-block mb-6">
            <img src={(displayUser?.avatar || (username ? `https://api.dicebear.com/7.x/avataaars/svg?seed=${username}` : '')) || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.username}`} className="w-32 h-32 rounded-full border-4 border-brand object-cover shadow-2xl" />
            {(displayUser?.subscription || !username) && (
              <div className="absolute -bottom-2 -right-2 bg-brand text-white p-2 rounded-xl shadow-lg">
                <Star size={18} fill="currentColor" />
              </div>
            )}
          </div>

          <h1 className="text-3xl font-black dark:text-white uppercase tracking-tighter mb-1 italic">{displayUser?.fullName || username || user?.fullName}</h1>
          <p className="text-[#CCCCCC] mb-8 font-bold">@{username || user?.username}</p>

          <div className="grid grid-cols-2 gap-4 mb-10">
             <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <div className="flex items-center justify-center gap-2 mb-1">
                   <Coins size={14} className="text-brand" />
                   <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Points</span>
                </div>
                <span className="text-3xl font-black text-brand">{isSelf ? user?.points : '1.2k'}</span>
             </div>
             <div className="p-6 bg-gray-50 dark:bg-gray-800 rounded-[2.5rem] border dark:border-gray-700">
                <div className="flex items-center justify-center gap-2 mb-1">
                   <Box size={14} className="text-brand" />
                   <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Ads</span>
                </div>
                <span className="text-3xl font-black text-brand">{userSpecificListings.length}</span>
             </div>
          </div>

          <div className="mb-10 text-left">
            <h2 className="text-lg font-black dark:text-white uppercase tracking-tighter mb-4 px-2">{lang === 'ar' ? 'أغراض للإيجار' : 'Items for Rent'}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {userSpecificListings.length === 0 ? (
                <div className="col-span-full py-10 bg-gray-50 dark:bg-gray-800 rounded-3xl text-center opacity-40">
                  <p className="text-[10px] font-black uppercase tracking-widest">{lang === 'ar' ? 'لا يوجد أغراض بعد' : 'No items listed yet'}</p>
                </div>
              ) : userSpecificListings.map(l => <ListingCard key={l.id} listing={l} lang={lang} isOwner={l.ownerId === user?.id} onDelete={(id) => setAllListings(prev => prev.filter(item => item.id !== id))} onAddPoints={addPoints} />)}
            </div>
          </div>

          {isSelf && (
            <div className="space-y-3 mb-10">
              <Link to="/subscription" className="w-full flex items-center justify-between p-6 bg-brand/5 border-2 border-brand/20 rounded-[2rem] hover:bg-brand text-brand hover:text-white transition-all group text-left">
                 <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-brand/10 text-brand flex items-center justify-center group-hover:bg-white/20 group-hover:text-white">
                      <Sparkles size={24} />
                    </div>
                    <div>
                      <span className="font-black uppercase tracking-tighter text-sm block">{lang === 'ar' ? 'استبدال النقاط' : 'Redeem Points'}</span>
                      <span className="text-[9px] font-bold opacity-60 uppercase">{lang === 'ar' ? 'احصل على اشتراكات وميزات' : 'Get exclusive tiers and features'}</span>
                    </div>
                 </div>
                 <ChevronRight />
              </Link>

              <div className="grid grid-cols-1 gap-2">
                 <Link to="/privacy" className="flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-800 rounded-1.8rem hover:bg-gray-100 transition-colors">
                   <span className="text-xs font-black uppercase tracking-widest dark:text-white">{t.privacyPolicy}</span>
                   <ChevronRight size={18} className="text-gray-400" />
                 </Link>
                 <Link to="/terms" className="flex items-center justify-between p-5 bg-gray-50 dark:bg-gray-800 rounded-1.8rem hover:bg-gray-100 transition-colors">
                   <span className="text-xs font-black uppercase tracking-widest dark:text-white">{t.termsOfUse}</span>
                   <ChevronRight size={18} className="text-gray-400" />
                 </Link>
              </div>
              <button onClick={() => setUser(null)} className="w-full mt-6 flex items-center justify-center gap-2 text-red-500 font-black uppercase tracking-widest text-[10px] hover:underline transition-all">
                {t.logout}
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  const SignUpPage = () => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [signupData, setSignupData] = useState({
      avatar: '', fullName: '', username: '', location: { address: '', lat: 0, lng: 0 },
      email: '', password: '', agreed: false
    });
    const [isLocating, setIsLocating] = useState(false);

    const handleAutoLocation = () => {
      setIsLocating(true);
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(async (position) => {
          const { latitude, longitude } = position.coords;
          try {
            const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&addressdetails=1&accept-language=${lang}`);
            const data = await response.json();
            const { address } = data;
            const country = address.country || '';
            const city = address.city || address.town || address.village || address.state || '';
            const neighborhood = address.suburb || address.neighbourhood || address.residential || address.road || '';
            const fullAddress = [country, city, neighborhood].filter(Boolean).join(', ');

            setSignupData(prev => ({
              ...prev,
              location: { address: fullAddress, lat: latitude, lng: longitude }
            }));
          } catch (e) {
             setSignupData(prev => ({
              ...prev,
              location: { address: `${latitude.toFixed(2)}, ${longitude.toFixed(2)}`, lat: latitude, lng: longitude }
            }));
          } finally {
            setIsLocating(false);
          }
        }, () => {
          alert(lang === 'ar' ? 'فشل جلب الموقع' : 'Location failed');
          setIsLocating(false);
        });
      }
    };

    return (
      <div className="w-full max-w-2xl px-6 py-12 mx-auto animate-in fade-in slide-in-from-bottom-8">
        <div className="text-center mb-10">
          <div className="inline-block px-4 py-2 bg-brand text-white rounded-2xl shadow-xl font-black text-2xl mb-4 italic">my rents</div>
          <h1 className="text-3xl font-black dark:text-white mb-2">{lang === 'ar' ? 'إنشاء حساب جديد' : 'Create New Account'}</h1>
        </div>
        <form onSubmit={(e) => handleSignUpFinish(e, signupData)} className="space-y-6">
          <div className="flex flex-col items-center gap-2">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="w-32 h-32 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center border-4 border-brand cursor-pointer overflow-hidden shadow-2xl relative group">
               {signupData.avatar ? <img src={signupData.avatar} className="w-full h-full object-cover" /> : <Camera size={40} className="text-gray-400 group-hover:scale-110 transition-transform" />}
               <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={e => {
                 /* Added type casting for EventTarget to HTMLInputElement to fix unknown type error on files */
                 const target = e.target as HTMLInputElement;
                 if (target.files && target.files.length > 0) {
                   setSignupData({...signupData, avatar: URL.createObjectURL(target.files[0])});
                 }
               }} />
            </button>
            <span className="text-[10px] font-black uppercase text-gray-400">{t.signupSteps.profilePic}</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input type="text" required placeholder={t.signupSteps.personalName} value={signupData.fullName} onChange={e => setSignupData({...signupData, fullName: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-sm" />
            <input type="text" required placeholder={t.signupSteps.userName} value={signupData.username} onChange={e => setSignupData({...signupData, username: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-sm" />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest block px-2">{t.location}</label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <MapPinned size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-brand" />
                <input 
                  type="text" 
                  required 
                  readOnly
                  placeholder={lang === 'ar' ? 'اضغط لتحديد الموقع الجغرافي...' : 'Tap to fetch structured address...'} 
                  value={signupData.location.address} 
                  className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand font-bold shadow-sm" 
                />
              </div>
              <button 
                type="button" 
                onClick={handleAutoLocation}
                className="p-4 bg-white dark:bg-gray-800 border-2 border-brand/20 text-brand rounded-2xl hover:bg-brand hover:text-white transition-all shadow-sm active:scale-90"
              >
                {isLocating ? <Loader2 size={24} className="animate-spin" /> : <MapPin size={24} />}
              </button>
            </div>
          </div>

          <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-2xl flex items-start gap-3 border dark:border-gray-700 shadow-inner">
             <input 
                type="checkbox" 
                id="agreed" 
                required 
                checked={signupData.agreed} 
                onChange={e => setSignupData({...signupData, agreed: e.target.checked})} 
                className="mt-1 w-5 h-5 accent-brand rounded cursor-pointer"
             />
             <label htmlFor="agreed" className="text-[11px] font-bold dark:text-white leading-relaxed cursor-pointer">
                {lang === 'ar' ? (
                  <>أوافق على <Link to="/privacy" className="text-brand underline">سياسة الخصوصية</Link> و <Link to="/terms" className="text-brand underline">شروط الاستخدام</Link></>
                ) : (
                  <>I agree to <Link to="/privacy" className="text-brand underline">Privacy Policy</Link> and <Link to="/terms" className="text-brand underline">Terms</Link></>
                )}
             </label>
          </div>

          <button type="submit" disabled={!signupData.fullName || !signupData.agreed} className="w-full py-5 bg-brand text-white rounded-[2.5rem] font-black shadow-xl shadow-brand/20 tracking-widest uppercase hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-30">
            {lang === 'ar' ? 'ابدأ رحلة الإيجار' : 'Get Started'}
          </button>
        </form>
      </div>
    );
  };

  return (
    <HashRouter>
      <div className={`min-h-screen ${lang === 'ar' ? 'rtl' : 'ltr'} bg-white dark:bg-gray-950 transition-colors duration-200`} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
        {user && <Navbar lang={lang} isDark={isDarkMode} toggleTheme={toggleTheme} user={user} />}
        <main className={user ? 'pb-20' : ''}>
          <Routes>
            <Route path="/" element={!user ? <SignUpPage /> : <HomePage lang={lang} user={user} userListings={allListings.filter(l => l.ownerId === user.id)} onDeleteListing={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
            <Route path="/privacy" element={<PrivacyPolicyPage lang={lang} />} />
            <Route path="/terms" element={<TermsOfUsePage lang={lang} />} />
            {user && (
              <>
                <Route path="/discovery" element={
                  <div className="p-8 animate-in fade-in">
                    <div className="text-center mb-12">
                      <Compass size={64} className="mx-auto text-brand mb-4 animate-spin-slow" />
                      <h1 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-2 italic">{t.discovery}</h1>
                      <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">{lang === 'ar' ? 'استكشف ما هو متاح بالقرب منك' : 'Explore what is available nearby'}</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 max-w-7xl mx-auto">
                      {allListings.length === 0 ? (
                         <div className="col-span-full py-20 text-center opacity-20">
                            <Box size={64} className="mx-auto mb-4" />
                            <p className="font-black uppercase tracking-widest text-sm">No items in your area yet</p>
                         </div>
                      ) : allListings.map(l => <ListingCard key={l.id} listing={l} lang={lang} isOwner={l.ownerId === user.id} onDelete={(id) => setAllListings(prev => prev.filter(item => item.id !== id))} onAddPoints={addPoints} />)}
                    </div>
                  </div>
                } />
                <Route path="/subscription" element={<SubscriptionPage lang={lang} user={user} onUpdateUser={setUser} />} />
                <Route path="/create" element={<CreateListingPage lang={lang} user={user} onCreated={(l) => { setAllListings(prev => [...prev, l]); addPoints(POINTS_SYSTEM.CREATE_LISTING); }} />} />
                <Route path="/chat/*" element={<ChatPage lang={lang} onAddPoints={addPoints} />} />
                <Route path="/item/:id" element={<ItemDetailPage lang={lang} user={user} listings={allListings} onDelete={(id) => setAllListings(prev => prev.filter(l => l.id !== id))} onAddPoints={addPoints} />} />
                <Route path="/profile/:username?" element={<ProfileView />} />
              </>
            )}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { useLocation as useRouteLocation } from 'react-router-dom';
import { translations } from '../i18n';
import { Mic, Image as ImageIcon, Video, Trash2, MapPin, Flag, ShieldBan, Send, Users, UserPlus, ShieldCheck, Camera, MoreVertical, CheckCircle2, MapPinned, Loader2, Star, PlayCircle, X } from 'lucide-react';
import { POINTS_SYSTEM } from '../constants';

interface ChatMessage {
  id: number;
  text?: string;
  sender: 'me' | 'other' | 'system';
  type: 'text' | 'image' | 'video' | 'location' | 'location_request';
  data?: string;
  timestamp: number;
}

const ChatPage: React.FC<{ lang: string; onAddPoints?: (a: number) => void }> = ({ lang, onAddPoints }) => {
  const t = translations[lang] || translations['en'];
  const routeLocation = useRouteLocation();
  const queryParams = new URLSearchParams(routeLocation.search);
  const itemId = queryParams.get('item');

  const [activeTab, setActiveTab] = useState<'PRIVATE' | 'GROUPS'>('PRIVATE');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLocating, setIsLocating] = useState(false);
  const [showGroupCreate, setShowGroupCreate] = useState(false);
  const [groupData, setGroupData] = useState({ name: '', description: '', image: '' });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = (type: ChatMessage['type'] = 'text', data?: string) => {
    if (type === 'text' && !input.trim()) return;

    const newMessage: ChatMessage = {
      id: Date.now(),
      text: type === 'text' ? input : undefined,
      data: data,
      sender: 'me',
      type,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    if (type === 'text') setInput('');

    if (type === 'text') {
      onAddPoints?.(POINTS_SYSTEM.MESSAGE);
    } else {
      onAddPoints?.(POINTS_SYSTEM.ATTACHMENT);
    }
  };

  const shareCurrentLocation = () => {
    setIsLocating(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const coords = `${pos.coords.latitude},${pos.coords.longitude}`;
          handleSend('location', coords);
          setIsLocating(false);
        },
        (err) => {
          const errMsg = lang === 'ar' 
            ? 'فشل جلب الموقع. تأكد من تفعيل إذن الوصول للموقع.' 
            : 'Location failed. Please enable GPS permissions.';
          alert(errMsg);
          setIsLocating(false);
        },
        { enableHighAccuracy: true, timeout: 5000 }
      );
    } else {
      alert(lang === 'ar' ? 'متصفحك لا يدعم تحديد الموقع' : 'Browser does not support geolocation');
      setIsLocating(false);
    }
  };

  const requestLocation = () => {
    handleSend('location_request');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'video') => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (type === 'video' && file.size > 20 * 1024 * 1024) {
      alert(lang === 'ar' ? 'حجم الفيديو كبير جداً (الأقصى 20 ميجابايت)' : 'Video too large (Max 20MB)');
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const dataUrl = event.target?.result as string;
      handleSend(type, dataUrl);
    };
    reader.onerror = () => {
      alert(lang === 'ar' ? 'خطأ في قراءة الملف' : 'Error reading file');
    };
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  const renderMessageContent = (m: ChatMessage) => {
    switch (m.type) {
      case 'location':
        return (
          <div className="space-y-3 min-w-[200px]">
            <div className="aspect-video bg-gray-200 dark:bg-gray-700 rounded-2xl flex items-center justify-center overflow-hidden relative">
               <MapPinned size={32} className="text-brand absolute z-10 animate-bounce" />
               <div className="absolute inset-0 bg-brand/5 backdrop-blur-[2px]" />
               <div className="grid grid-cols-4 grid-rows-4 gap-1 w-full h-full opacity-20">
                 {Array.from({ length: 16 }).map((_, i) => (
                   <div key={i} className="border border-brand/20" />
                 ))}
               </div>
            </div>
            <div className="px-1 text-center">
              <p className="text-[10px] font-black uppercase text-brand mb-2">{lang === 'ar' ? 'موقعي الحالي' : 'My Current Location'}</p>
              <a 
                href={`https://www.google.com/maps?q=${m.data}`} 
                target="_blank" 
                rel="noopener noreferrer"
                className="inline-flex items-center gap-2 px-4 py-2 bg-brand text-white rounded-xl text-[9px] font-black uppercase shadow-lg shadow-brand/20 hover:scale-105 transition-transform"
              >
                <MapPin size={10} /> {lang === 'ar' ? 'فتح الخرائط' : 'Open Maps'}
              </a>
            </div>
          </div>
        );
      case 'location_request':
        return (
          <div className="flex flex-col items-center gap-3 py-4 px-2 min-w-[220px]">
            <div className="w-14 h-14 bg-brand/10 rounded-[1.5rem] flex items-center justify-center text-brand animate-pulse">
              <MapPin size={28} />
            </div>
            <div className="text-center">
              <p className="font-black uppercase text-[11px] tracking-tighter dark:text-white mb-1">
                {lang === 'ar' ? 'طلب مشاركة الموقع' : 'Location Request'}
              </p>
              <p className="text-[9px] text-gray-400 font-bold leading-tight">
                {lang === 'ar' ? 'يطلب الطرف الآخر معرفة موقعك لتسهيل عملية الاستلام' : 'The other party requested your location for pickup.'}
              </p>
            </div>
            <button 
              onClick={shareCurrentLocation}
              className="w-full py-2.5 bg-brand/5 hover:bg-brand hover:text-white text-brand rounded-xl text-[10px] font-black uppercase transition-all"
            >
              {lang === 'ar' ? 'مشاركة الآن' : 'Share Now'}
            </button>
          </div>
        );
      case 'image':
        return (
          <div className="rounded-2xl overflow-hidden border-2 border-white dark:border-gray-800 bg-gray-100 dark:bg-gray-800 shadow-lg">
            <img src={m.data} alt="Attachment" className="w-full h-auto max-h-80 object-cover hover:scale-105 transition-transform duration-500 cursor-pointer" />
          </div>
        );
      case 'video':
        return (
          <div className="rounded-2xl overflow-hidden bg-black relative aspect-video flex items-center justify-center group shadow-xl border-2 border-white dark:border-gray-800">
            <video src={m.data} className="w-full h-full" controls />
          </div>
        );
      default:
        return <p className="whitespace-pre-wrap">{m.text}</p>;
    }
  };

  return (
    <div className="max-w-7xl mx-auto flex h-[calc(100vh-140px)] mt-2 bg-white dark:bg-gray-900 rounded-[3rem] overflow-hidden shadow-2xl border dark:border-gray-800 animate-in fade-in zoom-in-95 duration-500">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={(e) => handleFileUpload(e, 'image')} 
      />
      <input 
        type="file" 
        ref={videoInputRef} 
        className="hidden" 
        accept="video/*" 
        onChange={(e) => handleFileUpload(e, 'video')} 
      />

      <div className="w-80 border-r dark:border-gray-800 flex flex-col bg-gray-50/30 dark:bg-gray-950/40 shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-2 mb-6">
            <div className="w-8 h-8 bg-brand text-white rounded-lg flex items-center justify-center font-black italic text-xs rotate-3">R</div>
            <h1 className="text-xl font-black dark:text-white uppercase tracking-tighter">Chat Center</h1>
          </div>

          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-2xl mb-6">
            <button onClick={() => setActiveTab('PRIVATE')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'PRIVATE' ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>
              {lang === 'ar' ? 'رسائل' : 'Direct'}
            </button>
            <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'GROUPS' ? 'bg-white dark:bg-gray-900 text-brand shadow-sm' : 'text-gray-400'}`}>
              {t.groups}
            </button>
          </div>

          <div className="space-y-2">
             <div className="p-4 bg-brand/5 border border-brand/20 rounded-2xl flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-brand/10 flex items-center justify-center text-brand">
                  <Star size={20} fill="currentColor" />
                </div>
                <div>
                   <p className="text-[10px] font-black uppercase dark:text-white leading-none mb-1">AI Assistant</p>
                   <p className="text-[9px] font-bold text-gray-400">{t.online}</p>
                </div>
             </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-4 space-y-2">
          {activeTab === 'GROUPS' && (
            <button onClick={() => setShowGroupCreate(true)} className="w-full p-4 border-2 border-dashed dark:border-gray-800 rounded-2xl flex items-center justify-center gap-2 text-gray-400 font-bold text-[10px] uppercase hover:text-brand hover:border-brand transition-all">
               <UserPlus size={16} /> {t.createGroup}
            </button>
          )}
          <div className="py-20 text-center opacity-10">
            <Users size={48} className="mx-auto text-brand mb-2" />
            <p className="text-[9px] font-black uppercase dark:text-white tracking-widest">{lang === 'ar' ? 'لا توجد محادثات' : 'No chats'}</p>
          </div>
        </div>
      </div>

      <div className="flex-1 flex flex-col relative bg-white dark:bg-gray-900 min-w-0">
        <div className="p-4 border-b dark:border-gray-800 flex justify-between items-center bg-white/50 dark:bg-gray-900/50 backdrop-blur-md z-20">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-gray-100 dark:bg-gray-800 overflow-hidden border-2 border-brand/10">
                <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=Support`} className="w-full h-full object-cover" />
             </div>
             <div>
                <h2 className="font-black dark:text-white text-xs uppercase tracking-tighter flex items-center gap-1">
                   {t.chat} <CheckCircle2 size={12} className="text-blue-500" />
                </h2>
                <span className="text-[9px] text-green-500 font-black uppercase tracking-widest">{t.online}</span>
             </div>
          </div>
          <div className="flex gap-1">
             <button className="p-2 text-gray-400 hover:text-brand transition-all" onClick={() => alert(lang === 'ar' ? 'تم تقديم بلاغ' : 'Report submitted')}><Flag size={18} /></button>
             <button className="p-2 text-gray-400 hover:text-brand transition-all"><MoreVertical size={18} /></button>
          </div>
        </div>

        {itemId && (
          <div className="p-3 bg-brand/5 border-b border-brand/10 flex items-center justify-between animate-in slide-in-from-top duration-300">
             <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-white dark:bg-gray-800 rounded-lg overflow-hidden border border-brand/20">
                   <img src="https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&q=80&w=100" className="w-full h-full object-cover" />
                </div>
                <div>
                   <p className="text-[9px] font-black text-brand uppercase tracking-widest leading-none mb-1">{t.itemDiscussion}</p>
                   <p className="text-[11px] font-bold dark:text-white">Professional Camera Rig</p>
                </div>
             </div>
             <button onClick={() => alert(t.confirmRental)} className="px-4 py-1.5 bg-brand text-white rounded-xl text-[9px] font-black uppercase shadow-lg shadow-brand/20 active:scale-95 transition-all">
                {t.confirmRental}
             </button>
          </div>
        )}

        <div className="flex-1 p-6 overflow-y-auto space-y-4 bg-gray-50/20 dark:bg-gray-900/20">
           {messages.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center text-center p-10 opacity-30 select-none">
                <ShieldCheck size={64} className="text-brand mb-4 animate-pulse" />
                <h3 className="text-sm font-black uppercase tracking-tighter mb-2 dark:text-white">
                  {lang === 'ar' ? 'ابدأ محادثة آمنة' : 'Start Secure Chat'}
                </h3>
                <p className="text-[10px] font-bold dark:text-white max-w-[240px] leading-relaxed">
                  {lang === 'ar' 
                    ? 'جميع المحادثات مراقبة بواسطة ذكاء my rents لضمان عملية استئجار ناجحة وآمنة.' 
                    : 'All conversations are monitored by my rents AI to ensure a successful and safe rental process.'}
                </p>
             </div>
           ) : (
             messages.map(m => (
               <div key={m.id} className={`flex flex-col ${m.sender === 'me' ? 'items-end' : m.sender === 'system' ? 'items-center' : 'items-start'} animate-in slide-in-from-bottom-2`}>
                  {m.sender === 'system' ? (
                    <div className="px-4 py-1.5 bg-gray-100 dark:bg-gray-800 rounded-full text-[9px] font-black uppercase text-gray-400 border dark:border-gray-700 my-2">
                       {m.text}
                    </div>
                  ) : (
                    <div className={`max-w-[85%] sm:max-w-[70%] group relative`}>
                      <div className={`p-4 rounded-[1.8rem] shadow-sm text-xs font-bold leading-relaxed ${m.sender === 'me' ? 'bg-brand text-white rounded-tr-none' : 'bg-white dark:bg-gray-800 dark:text-white border dark:border-gray-700 rounded-tl-none'}`}>
                         {renderMessageContent(m)}
                      </div>
                      <span className={`text-[8px] font-black text-gray-300 uppercase mt-1 px-2 block ${m.sender === 'me' ? 'text-right' : 'text-left'}`}>
                         {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  )}
               </div>
             ))
           )}
           <div ref={chatEndRef} />
        </div>

        <div className="p-6 border-t dark:border-gray-800 bg-white/50 dark:bg-gray-900/50 backdrop-blur-md">
           <div className="flex items-center gap-2 mb-4 overflow-x-auto pb-2 scrollbar-hide">
              <button 
                onClick={shareCurrentLocation} 
                disabled={isLocating}
                className="shrink-0 flex items-center gap-2 px-4 py-2.5 bg-brand/5 text-brand rounded-2xl text-[10px] font-black uppercase hover:bg-brand hover:text-white transition-all disabled:opacity-50"
              >
                {isLocating ? <Loader2 size={14} className="animate-spin" /> : <MapPin size={14} />} {t.location}
              </button>
              <button 
                onClick={requestLocation} 
                className="shrink-0 flex items-center gap-2 px-4 py-2.5 bg-gray-50 dark:bg-gray-800 text-gray-500 dark:text-gray-400 rounded-2xl text-[10px] font-black uppercase hover:text-brand hover:bg-brand/5 transition-all"
              >
                 <MapPinned size={14} /> {t.requestLocation}
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()} 
                className="shrink-0 flex items-center gap-2 px-4 py-2.5 bg-gray-50 dark:bg-gray-800 text-gray-500 dark:text-gray-400 rounded-2xl text-[10px] font-black uppercase hover:text-brand hover:bg-brand/5 transition-all"
              >
                 <Camera size={14} /> {lang === 'ar' ? 'صورة' : 'Snap'}
              </button>
              <button 
                onClick={() => videoInputRef.current?.click()} 
                className="shrink-0 flex items-center gap-2 px-4 py-2.5 bg-gray-50 dark:bg-gray-800 text-gray-500 dark:text-gray-400 rounded-2xl text-[10px] font-black uppercase hover:text-brand hover:bg-brand/5 transition-all"
              >
                 <Video size={14} /> {lang === 'ar' ? 'فيديو' : 'Video'}
              </button>
           </div>

           <div className="flex gap-3">
              <div className="flex-1 relative group">
                <input 
                  type="text" 
                  value={input} 
                  onChange={e => setInput(e.target.value)} 
                  onKeyDown={e => e.key === 'Enter' && handleSend()} 
                  className="w-full bg-gray-100 dark:bg-gray-800 dark:text-white px-8 py-5 rounded-[2.2rem] outline-none font-bold text-sm shadow-inner focus:ring-2 focus:ring-brand transition-all pr-14" 
                  placeholder={lang === 'ar' ? 'اكتب رسالتك بأمان...' : 'Secure message...'} 
                />
                <button 
                  onClick={() => alert(lang === 'ar' ? 'ميزة الصوت قيد التحسين' : 'Audio feature coming soon')}
                  className="absolute right-5 top-1/2 -translate-y-1/2 p-2 text-gray-400 hover:text-brand transition-colors"
                >
                  <Mic size={22} />
                </button>
              </div>
              <button 
                onClick={() => handleSend()} 
                className="w-16 h-16 bg-brand text-white rounded-[2rem] shadow-xl shadow-brand/20 active:scale-90 transition-all flex items-center justify-center shrink-0"
              >
                 <Send size={28} />
              </button>
           </div>

           <div className="flex items-center justify-center gap-2 mt-4 opacity-30 select-none">
              <ShieldCheck size={12} className="text-brand" />
              <span className="text-[8px] font-black uppercase tracking-widest dark:text-white">AI Protected Interaction Layer</span>
           </div>
        </div>
      </div>

      {showGroupCreate && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/70 backdrop-blur-md">
           <div className="bg-white dark:bg-gray-900 w-full max-w-md rounded-[3.5rem] p-10 shadow-2xl animate-in zoom-in-95">
              <h3 className="text-2xl font-black mb-8 dark:text-white text-center uppercase tracking-tighter italic">{t.createGroup}</h3>
              <div className="space-y-4">
                 <button 
                   type="button" 
                   onClick={() => fileInputRef.current?.click()} 
                   className="w-24 h-24 rounded-[2rem] bg-gray-100 dark:bg-gray-800 mx-auto flex items-center justify-center border-4 border-dashed border-brand cursor-pointer overflow-hidden relative group"
                 >
                   {groupData.image ? <img src={groupData.image} className="w-full h-full object-cover" /> : <Camera size={32} className="text-gray-400" />}
                   <input type="file" className="hidden" accept="image/*" onChange={e => {
                     /* Added type casting for EventTarget to HTMLInputElement to fix unknown type error on files */
                     const target = e.target as HTMLInputElement;
                     if (target.files && target.files.length > 0) {
                       setGroupData({...groupData, image: URL.createObjectURL(target.files[0])});
                     }
                   }} />
                 </button>
                 <input type="text" placeholder={lang === 'ar' ? 'اسم المجتمع*' : 'Community Name*'} value={groupData.name} onChange={e => setGroupData({...groupData, name: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white outline-none font-bold shadow-sm" />
                 <textarea placeholder={lang === 'ar' ? 'وصف المجتمع*' : 'Description*'} value={groupData.description} onChange={e => setGroupData({...groupData, description: e.target.value})} className="w-full p-4 rounded-2xl bg-gray-50 dark:bg-gray-800 dark:text-white h-24 outline-none font-bold shadow-sm" />
                 <button onClick={() => { alert(lang === 'ar' ? 'تم إنشاء المجموعة!' : 'Community created!'); setShowGroupCreate(false); }} disabled={!groupData.name || !groupData.image} className="w-full py-5 bg-brand text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all">Launch Community</button>
                 <button onClick={() => setShowGroupCreate(false)} className="w-full py-2 text-gray-400 font-black text-[10px] uppercase tracking-widest">{t.back}</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default ChatPage;
